import { useState, useRef, useEffect } from 'react';
import TinderCard from 'react-tinder-card';
import { useRouter } from 'next/router';
import styles from '../styles/Home.module.css';

export default function MenuEditor() {
  const router = useRouter();
  const [slug, setSlug] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const pinRef = useRef(null);

  const [pinEntered, setPinEntered] = useState(false);
  const [pin, setPin] = useState('');
  const [restaurant, setRestaurant] = useState({
    name: '',
    icon: '🍽️',
    tagline: ''
  });

  const [gallery, setGallery] = useState([]);
  const [sections, setSections] = useState([]);
  const [items, setItems] = useState([]);

  const [editingItem, setEditingItem] = useState(null);
  const [newItem, setNewItem] = useState({ section: '', name: '', price: '', desc: '', image: null });
  const [view, setView] = useState('editor');
  const [selectedSection, setSelectedSection] = useState('');
  const [lastAction, setLastAction] = useState(null);
  const fileInputRef = useRef(null);
  const swipeRef = useRef([]);

  // Load data on mount
  useEffect(() => {
    // Pre-seed Gulf Island Grill on first load
    if (!localStorage.getItem('menu_gulfislandgrill')) {
      const gulfData = {
        restaurant: { name: 'Gulf Island Grill', icon: '🍽️', tagline: 'Fresh Gulf Coast Flavors' },
        sections: ['Soups', 'Salads', 'From the Grill', 'House Specialties', 'Sandwiches', 'From the Fryer', 'Pasta', 'From the Steamer', 'Desserts', 'Drinks'],
        items: [
          { id: 1, section: 'Soups', name: 'Crab and Corn Bisque', price: '$8/$12', desc: 'Creamy crab meat treasure served with crackers.', image: null },
          { id: 2, section: 'Soups', name: 'Seafood Gumbo', price: '$8/$12', desc: 'Made from scratch shrimp & sausage gumbo served with crackers.', image: null },
          { id: 3, section: 'Salads', name: 'The Grill Salad', price: '$17', desc: 'Fresh tossed greens with grilled chicken, craisins, pineapple, parmesan cheese, and toasted almonds.', image: null },
          { id: 4, section: 'Salads', name: 'Mango Shrimp Salad', price: '$17', desc: 'Fresh greens with red onions, cherry tomatoes, boiled egg, parmesan cheese topped with mango BBQ shrimp.', image: null },
          { id: 5, section: 'Salads', name: 'Tender Salad', price: '$16', desc: 'Fresh greens with red onions, cherry tomatoes, boiled egg, parmesan cheese topped with crispy fried chicken.', image: null },
          { id: 6, section: 'From the Grill', name: 'Islamorada Chicken', price: '$20', desc: 'Grilled chicken breast marinated with island flavors. Served with Caribbean rice, steamed veggies, and grilled pineapple.', image: null },
          { id: 7, section: 'From the Grill', name: 'Ribeye', price: '$30', desc: 'Hand cut and grilled to your liking, served with mashed potatoes and steamed veggies.', image: null },
          { id: 8, section: 'From the Grill', name: 'Caribbean Shrimp Kabobs', price: '$24', desc: '2 grilled shrimp skewers with Caribbean rice, steamed veggies, and grilled pineapple.', image: null },
          { id: 9, section: 'From the Grill', name: 'Surf and Turf', price: '$36', desc: '12oz ribeye with your choice of grilled shrimp skewer, fried shrimp, or stuffed crab. Served with Gulf Island potatoes and steamed veggies.', image: null },
          { id: 10, section: 'From the Grill', name: 'Mahi Tacos', price: '$22', desc: 'Fresh mahi mahi wrapped in flour tortilla with homemade pico de gallo, fresh lettuce, and cheese. Served with chips and salsa.', image: null },
          { id: 11, section: 'From the Grill', name: 'Baja Catch', price: '$22', desc: 'Fresh fish prepared grilled or blackened. Served with Caribbean rice and steamed veggies.', image: null },
          { id: 12, section: 'From the Grill', name: 'Shrimp Scampi', price: '$22', desc: 'Fresh gulf shrimp sautéed in garlic wine butter. Served with Caribbean rice and steamed veggies.', image: null },
          { id: 13, section: 'House Specialties', name: 'Grouper Roulade', price: '$24', desc: 'Fresh grouper stuffed with crabmeat and broiled in garlic-wine butter cream sauce. Served with mashed potatoes and steamed veggies.', image: null },
          { id: 14, section: 'House Specialties', name: 'Baby Back Ribs', price: '$28', desc: 'Full 2 lb rack rubbed with island spices and slow cooked. Served with fries and Key West slaw.', image: null },
          { id: 15, section: 'House Specialties', name: 'Grouper Parmesan', price: '$24', desc: 'Baked grouper topped with fresh parmesan. Served with mashed potatoes and steamed veggies.', image: null },
          { id: 16, section: 'House Specialties', name: 'Gulf Island Ya-Ya', price: '$23', desc: 'Shrimp, chicken, Andouille sausage, peppers, onions, and tomatoes in garlic cheddar sauce on Caribbean rice. Served with garlic bread.', image: null },
          { id: 17, section: 'House Specialties', name: 'Gulf Island Catch', price: '$22', desc: 'Voted one of the BEST dishes on the island. Lightly pan-fried fish topped with creamy shrimp & andouille sausage sauce. Served with steamed veggies.', image: null },
          { id: 18, section: 'House Specialties', name: 'Coconut Shrimp', price: '$14', desc: 'Homemade with crispy coconut batter. Served with homemade Jezabel sauce.', image: null },
          { id: 19, section: 'House Specialties', name: 'Buffalo Shrimp', price: '$14', desc: 'Hearty portion of popcorn shrimp tossed in honey BBQ, mango BBQ, or hot sauce.', image: null },
          { id: 20, section: 'Sandwiches', name: 'Po\'Boys', price: '$17', desc: 'Shrimp, crawfish, or grouper served on French loaf with lettuce, tomato, and onion.', image: null },
          { id: 21, section: 'Sandwiches', name: 'Jerk Chicken Sandwich', price: '$15', desc: 'Marinated chicken breast with grilled pineapple on toasted buns with lettuce, tomato, and onion.', image: null },
          { id: 22, section: 'Sandwiches', name: 'Island Burger', price: '$14', desc: '1/2 lb burger grilled with island spices. Customize with cheese, bacon, mushrooms, or pineapple.', image: null },
          { id: 23, section: 'From the Fryer', name: 'Fried Gulf Shrimp', price: '$22', desc: '10 golden brown shrimp served with cocktail sauce.', image: null },
          { id: 24, section: 'From the Fryer', name: 'Fried Grouper', price: '$20', desc: 'Fresh and local grouper cut into thin strips. Served with tartar sauce.', image: null },
          { id: 25, section: 'From the Fryer', name: 'Fried Chicken Tenders', price: '$17', desc: 'Fried, juicy chicken tenders. Served with homemade honey mustard.', image: null },
          { id: 26, section: 'From the Fryer', name: 'Bon Secour Platter', price: '$26', desc: 'Fried grouper strips, crawfish tails, gulf shrimp, and stuffed crab.', image: null },
          { id: 27, section: 'Pasta', name: 'Seafood Pasta', price: '$24', desc: 'Steamed shrimp & crawfish tails tossed in parmesan sauce with peppers and onions over penne noodles.', image: null },
          { id: 28, section: 'Pasta', name: 'Chicken Alfredo', price: '$22', desc: 'Grilled chicken tossed in parmesan sauce with peppers and onions over penne noodles. Served with french fries and slaw.', image: null },
          { id: 29, section: 'Pasta', name: 'Blackened Chicken Alfredo', price: '$22', desc: 'Creole-style blackened chicken tossed in parmesan sauce with peppers and onions over penne noodles.', image: null },
          { id: 30, section: 'From the Steamer', name: 'Boiled Shrimp Dinner', price: '$24', desc: 'Fresh local shrimp steamed with Old Bay. Served with new potatoes, corn, lemons, drawn butter, and hushpuppy.', image: null },
          { id: 31, section: 'From the Steamer', name: 'Snow Crab Legs', price: 'Market Price', desc: 'Your choice of 1 lb or 2 lb steamed crab legs with Old Bay. Served with potatoes, corn, lemons, and drawn butter.', image: null },
          { id: 32, section: 'Desserts', name: 'Peanut Butter Pie', price: '$7.99', desc: 'Creamy peanut butter pie drizzled with chocolate syrup with chocolate cracker crust.', image: null },
          { id: 33, section: 'Desserts', name: 'Salted Caramel Cheesecake', price: '$7.99', desc: 'Creamy, rich cheesecake with smooth caramel and a hint of sea salt.', image: null },
          { id: 34, section: 'Desserts', name: 'Key Lime Pie', price: '$7.99', desc: 'A classic made with graham cracker crust and drizzled with kiwi syrup.', image: null }
        ],
        gallery: [],
        pin: '1234'
      };
      localStorage.setItem('menu_gulfislandgrill', JSON.stringify(gulfData));
    }

    const businessSlug = new URLSearchParams(window.location.search).get('slug');
    if (!businessSlug) {
      router.replace('/?slug=gulfislandgrill');
      return;
    }
    setSlug(businessSlug);

    const loadData = () => {
      try {
        const stored = localStorage.getItem(`menu_${businessSlug}`);
        if (!stored) {
          router.replace('/new');
          return;
        }
        const data = JSON.parse(stored);
        pinRef.current = data.pin;
        setRestaurant(data.restaurant);
        setSections(data.sections);
        setItems(data.items);
        setGallery(data.gallery);
        setSelectedSection(data.sections[0] || '');
        setNewItem({ section: data.sections[0] || '', name: '', price: '', desc: '', image: null });
      } catch (err) {
        console.error('Load failed:', err);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  // PIN handler
  const handlePinSubmit = (e) => {
    e.preventDefault();
    if (pin === pinRef.current) {
      setPinEntered(true);
    } else {
      alert('Invalid PIN');
      setPin('');
    }
  };

  // Image upload
  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const newImage = {
        id: Math.max(...gallery.map(g => g.id || 0), 0) + 1,
        url: event.target.result,
        name: file.name
      };
      setGallery([...gallery, newImage]);
    };
    reader.readAsDataURL(file);
  };

  // Item handlers
  const addItem = () => {
    if (!newItem.name || !newItem.price || newItem.image === null) {
      alert('Fill all fields');
      return;
    }
    const item = {
      id: Math.max(...items.map(i => i.id), 0) + 1,
      ...newItem
    };
    setItems([...items, item]);
    setNewItem({ section: 'Seafood', name: '', price: '', desc: '', image: null });
  };

  const updateItem = () => {
    if (!editingItem.name || !editingItem.price || editingItem.image === null) {
      alert('Fill all fields');
      return;
    }
    setItems(items.map(i => i.id === editingItem.id ? editingItem : i));
    setEditingItem(null);
  };

  const deleteItem = (id) => {
    setItems(items.filter(i => i.id !== id));
  };

  // Swipe handlers
  const itemsToShow = items.filter(i => i.section === selectedSection);

  const handleSwipe = (direction, item) => {
    setLastAction(direction === 'right' ? 'like' : 'nope');
    setTimeout(() => setLastAction(null), 1000);
  };

  const handleCardLeftScreen = (item) => {
    // Card removed, next one will show automatically
  };

  // Publish/Save data
  const publishMenu = async () => {
    setSaving(true);
    try {
      const data = { restaurant, sections, items, gallery, pin: pinRef.current };
      localStorage.setItem(`menu_${slug}`, JSON.stringify(data));
      alert('✅ Saved!');
    } catch (err) {
      alert('Save error: ' + err.message);
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className={styles.pinScreen}>
        <div className={styles.pinBox}>
          <h1>Loading...</h1>
        </div>
      </div>
    );
  }

  if (!pinEntered) {
    return (
      <div className={styles.pinScreen}>
        <div className={styles.pinBox}>
          <h1>🔐 Menu Editor</h1>
          <p>Enter PIN to continue</p>
          <form onSubmit={handlePinSubmit}>
            <input
              type="password"
              value={pin}
              onChange={(e) => setPin(e.target.value)}
              placeholder="Enter PIN"
              maxLength="4"
              autoFocus
            />
            <button type="submit">Unlock</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <h1>{restaurant.icon} {restaurant.name}</h1>
        <p>{restaurant.tagline}</p>
        <div className={styles.tabs}>
          <button className={view === 'editor' ? styles.active : ''} onClick={() => setView('editor')}>
            ✏️ Edit
          </button>
          <button className={view === 'preview' ? styles.active : ''} onClick={() => setView('preview')}>
            👁️ Preview
          </button>
        </div>
      </header>

      {view === 'editor' ? (
        <div className={styles.editor}>
          {/* IMAGE GALLERY */}
          <section className={styles.section}>
            <h2>📷 Image Gallery</h2>
            <button onClick={() => fileInputRef.current.click()} className={styles.uploadBtn}>
              + Upload Image
            </button>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              onChange={handleImageUpload}
              style={{ display: 'none' }}
            />
            <div className={styles.gallery}>
              {gallery.map((img) => (
                <div key={img.id} className={styles.galleryItem}>
                  <img src={img.url} alt={img.name} />
                  <p>{img.name}</p>
                  <button
                    onClick={() => setGallery(gallery.filter(g => g.id !== img.id))}
                    className={styles.deleteBtn}
                  >
                    ✕
                  </button>
                </div>
              ))}
            </div>
          </section>

          {/* MENU ITEMS EDITOR */}
          <section className={styles.section}>
            <h2>🍽️ Menu Items</h2>

            {/* Add/Edit Form */}
            <div className={styles.form}>
              <h3>{editingItem ? 'Edit Item' : 'Add New Item'}</h3>
              <div className={styles.formGrid}>
                <select
                  value={editingItem ? editingItem.section : newItem.section}
                  onChange={(e) => editingItem
                    ? setEditingItem({...editingItem, section: e.target.value})
                    : setNewItem({...newItem, section: e.target.value})
                  }
                >
                  {sections.map(s => <option key={s}>{s}</option>)}
                </select>

                <input
                  type="text"
                  placeholder="Item name"
                  value={editingItem ? editingItem.name : newItem.name}
                  onChange={(e) => editingItem
                    ? setEditingItem({...editingItem, name: e.target.value})
                    : setNewItem({...newItem, name: e.target.value})
                  }
                />

                <input
                  type="text"
                  placeholder="Price"
                  value={editingItem ? editingItem.price : newItem.price}
                  onChange={(e) => editingItem
                    ? setEditingItem({...editingItem, price: e.target.value})
                    : setNewItem({...newItem, price: e.target.value})
                  }
                />

                <select
                  value={editingItem ? (editingItem.image || '') : (newItem.image || '')}
                  onChange={(e) => editingItem
                    ? setEditingItem({...editingItem, image: e.target.value})
                    : setNewItem({...newItem, image: e.target.value})
                  }
                >
                  <option value="">Select Image</option>
                  {gallery.map(img => (
                    <option key={img.id} value={img.url}>{img.name}</option>
                  ))}
                </select>

                <textarea
                  placeholder="Description"
                  value={editingItem ? editingItem.desc : newItem.desc}
                  onChange={(e) => editingItem
                    ? setEditingItem({...editingItem, desc: e.target.value})
                    : setNewItem({...newItem, desc: e.target.value})
                  }
                />

                <div className={styles.formButtons}>
                  {editingItem ? (
                    <>
                      <button onClick={updateItem} className={styles.saveBtn}>Save</button>
                      <button onClick={() => setEditingItem(null)} className={styles.cancelBtn}>Cancel</button>
                    </>
                  ) : (
                    <button onClick={addItem} className={styles.addBtn}>Add Item</button>
                  )}
                </div>
              </div>
            </div>

            {/* Items List */}
            <div className={styles.itemsList}>
              {sections.map(section => (
                <div key={section}>
                  <h4>{section}</h4>
                  {items.filter(i => i.section === section).map(item => (
                      <div key={item.id} className={styles.itemRow}>
                        {item.image && <img src={item.image} alt={item.name} />}
                        <div className={styles.itemInfo}>
                          <div className={styles.itemName}>{item.name}</div>
                          <div className={styles.itemMeta}>{item.price} • {item.desc.substring(0, 40)}...</div>
                        </div>
                        <div className={styles.itemActions}>
                          <button onClick={() => setEditingItem(item)} className={styles.editBtn}>Edit</button>
                          <button onClick={() => deleteItem(item.id)} className={styles.delBtn}>Delete</button>
                        </div>
                      </div>
                    ))}
                </div>
              ))}
            </div>
          </section>

          {/* PUBLISH */}
          <section className={styles.section}>
            <button onClick={publishMenu} className={styles.publishBtn}>
              📤 Publish to API
            </button>
          </section>
        </div>
      ) : (
        // CUSTOMER PREVIEW WITH SWIPE
        <div className={styles.preview}>
          <div className={styles.categoryNav}>
            {sections.map(section => (
              <button
                key={section}
                onClick={() => setSelectedSection(section)}
                className={selectedSection === section ? styles.activeCategory : ''}
              >
                {section}
              </button>
            ))}
          </div>

          {lastAction && (
            <div className={`${styles.swipeFlash} ${styles[lastAction]}`}>
              {lastAction === 'like' ? '❤️ LIKE' : '✕ NOPE'}
            </div>
          )}

          <div className={styles.cardsContainer}>
            {itemsToShow.length === 0 ? (
              <div className={styles.empty}>No items in this section</div>
            ) : (
              itemsToShow.map((item) => (
                  <TinderCard
                    key={item.id}
                    onSwipe={(dir) => handleSwipe(dir, item)}
                    onCardLeftScreen={() => handleCardLeftScreen(item)}
                    preventSwipe={['up', 'down']}
                    className={styles.tinderCard}
                  >
                    <div className={styles.swipeCardContent}>
                      {item.image && (
                        <img src={item.image} alt={item.name} className={styles.swipeImg} />
                      )}
                      <div className={styles.cardBody}>
                        <h2>{item.name}</h2>
                        <p className={styles.cardPrice}>{item.price}</p>
                        <p className={styles.cardDesc}>{item.desc}</p>
                      </div>
                    </div>
                  </TinderCard>
                ))
            )}
          </div>

          <div className={styles.swipeHint}>
            <span className={styles.hintNope}>← NOPE</span>
            <span className={styles.hintLike}>LIKE →</span>
          </div>
        </div>
      )}
    </div>
  );
}
